import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import API from '../../services/axios';

function ManageEvents() {
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => { fetchEvents(); }, []);

  const fetchEvents = async () => {
    try {
      const res = await API.get('/events');
      setEvents(res.data.events || []);
    } catch { }
    finally { setLoading(false); }
  };

  const handleDelete = async (id, name) => {
    if (!window.confirm(`Delete "${name}"?`)) return;
    try {
      await API.delete(`/events/${id}`);
      setEvents(events.filter(e => e._id !== id));
    } catch { alert('Failed to delete'); }
  };

  if (loading) return (
    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: '100vh' }}>
      <p style={{ color: '#6b7280' }}>Loading events...</p>
    </div>
  );

  return (
    <div style={{ padding: '2rem', background: '#f8f7ff', minHeight: '100vh' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
        <div>
          <h1 style={{ fontSize: '1.5rem', fontWeight: '800', color: '#1e1b4b' }}>EVENTS</h1>
          <p style={{ color: '#6b7280', fontSize: '0.85rem' }}>{events.length} events</p>
        </div>
        <Link to="/admin/create-event" style={{
          background: 'linear-gradient(135deg, #7c3aed, #a78bfa)',
          color: 'white', padding: '10px 20px', borderRadius: '10px',
          textDecoration: 'none', fontWeight: '600', fontSize: '0.85rem'
        }}>➕ Create Event</Link>
      </div>

      {events.length === 0 ? (
        <div style={{ background: 'white', borderRadius: '16px', padding: '4rem', textAlign: 'center' }}>
          <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>📭</div>
          <h2 style={{ color: '#1e1b4b', marginBottom: '1rem' }}>No Events Yet</h2>
          <Link to="/admin/create-event" style={{ background: '#7c3aed', color: 'white', padding: '10px 24px', borderRadius: '10px', textDecoration: 'none' }}>
            Create First Event
          </Link>
        </div>
      ) : (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '1.5rem' }}>
          {events.map(event => (
            <div key={event._id} style={{ background: 'white', borderRadius: '16px', overflow: 'hidden', boxShadow: '0 2px 10px rgba(0,0,0,0.06)' }}>
              <img src={event.image || 'https://via.placeholder.com/400x180?text=Event'}
                alt={event.name} style={{ width: '100%', height: '160px', objectFit: 'cover' }} />
              <div style={{ padding: '1rem' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.5rem' }}>
                  <span style={{ background: '#f5f3ff', color: '#7c3aed', fontSize: '0.7rem', fontWeight: '700', padding: '3px 10px', borderRadius: '20px' }}>{event.category}</span>
                  <span style={{
                    fontSize: '0.7rem', fontWeight: '700', padding: '3px 10px', borderRadius: '20px',
                    background: event.status === 'upcoming' ? '#d1fae5' : '#fee2e2',
                    color: event.status === 'upcoming' ? '#065f46' : '#991b1b'
                  }}>{event.status}</span>
                </div>
                <h3 style={{ fontWeight: '700', color: '#1f2937', marginBottom: '0.5rem', fontSize: '0.95rem' }}>{event.name}</h3>
                <p style={{ color: '#6b7280', fontSize: '0.8rem' }}>{event.description?.slice(0, 50)}...</p>
                <div style={{ marginTop: '0.5rem', fontSize: '0.75rem', color: '#9ca3af' }}>
                  <p>📅 {new Date(event.date).toLocaleDateString()} • {event.time}</p>
                  <p>📍 {event.venue}</p>
                  <p style={{ color: '#7c3aed', fontWeight: '700', fontSize: '0.85rem' }}>₹{event.price}</p>
                </div>
                <div style={{ display: 'flex', gap: '8px', marginTop: '1rem' }}>
                  <button onClick={() => handleDelete(event._id, event.name)} style={{
                    flex: 1, background: '#fee2e2', color: '#991b1b', border: 'none',
                    padding: '8px', borderRadius: '8px', cursor: 'pointer', fontWeight: '600', fontSize: '0.8rem'
                  }}>Delete</button>
                  <Link to={`/admin/edit-event/${event._id}`} style={{
                    flex: 1, background: '#dbeafe', color: '#1d4ed8', textAlign: 'center',
                    padding: '8px', borderRadius: '8px', textDecoration: 'none', fontWeight: '600', fontSize: '0.8rem'
                  }}>Edit</Link>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
export default ManageEvents;
